let incode,session,container=document.getElementById("incode-container");const UiConfig={branding:{logo:{src:"https://bancrea.com/wp-content/uploads/2024/03/logo-bancrea-1.png",height:"50px"},hideFooterBranding:!0}};function notifyCompletion(n){const e=new CustomEvent("incodeCompleted",{detail:n});window.dispatchEvent(e)}function waitForIncode(n=50){return new Promise((e,o)=>{const t=setInterval(()=>{window.OnBoarding?(clearInterval(t),e(window.OnBoarding)):n--<=0&&(clearInterval(t),o(new Error("Incode SDK not loaded")))},100)})}async function init(){session={token:document.getElementById("incode-config").value},console.log(session);const n=await waitForIncode();incode=await n.create({apiURL:"https://demo-api.incodesmile.com/0"}),await sendGeo()}async function sendGeo(){await incode.sendFingerprint({token:session.token}).catch(console.error),await incode.sendGeolocation({token:session.token}).catch(console.error),renderID()}function renderID(){incode.renderCaptureId(container,{session:session,onSuccess:renderFace,onError:console.error,forceIdV2:!0,uiConfig:UiConfig})}function renderFace(){incode.renderCaptureFace(container,{session:session,onSuccess:doFaceMatch,onError:console.error})}async function doFaceMatch(){await incode.processFace({token:session.token}),await incode.processId({token:session.token}),notifyCompletion({token:session.token,status:"completed"})}function waitForContainer(){document.getElementById("incode-container")?init():setTimeout(waitForContainer,100)}"loading"===document.readyState?document.addEventListener("DOMContentLoaded",waitForContainer):waitForContainer();